# ── CLI ───────────────────────────────────────────────────────────────────────

def main():
    p = argparse.ArgumentParser(
        description="Moreno AI Agent Identity Loader — Phase 9E.1",
        epilog="Personality is data, not code. All values read from files.")
    p.add_argument("--list",     action="store_true", help="List available agents")
    p.add_argument("--show",     metavar="AGENT",     help="Show identity summary")
    p.add_argument("--validate", metavar="AGENT",
                   help="Validate agent identity (use 'all')")
    p.add_argument("--all",      action="store_true", help="Load all agents")
    p.add_argument("--json",     action="store_true", help="Output as JSON")
    p.add_argument("--export",   metavar="PATH",      help="Export JSON to file")
    p.add_argument("--repo",     metavar="PATH",
                   help="Repository root (default: auto-detected)")
    args = p.parse_args()
    root = Path(args.repo) if args.repo else REPO_ROOT

    if args.list:
        adir = root / "agents"
        if not adir.exists():
            print("No agents/ directory at " + str(adir))
            sys.exit(1)
        for e in sorted(adir.iterdir()):
            if e.is_dir() and not e.name.startswith('.'):
                print(e.name.capitalize())
        return

    if args.all or args.validate == "all":
        eco = load_all_agents(repo_root=root)
        if not eco:
            print("No agents found.")
            return
        passed = sum(1 for i in eco.values() if i["validation"]["passed"])
        for name, identity in eco.items():
            if args.json:
                print(json.dumps(identity, indent=2))
            else:
                s = "v" if identity["validation"]["passed"] else "x"
                w = ("  [" + str(len(identity["validation"]["warnings"])) + "w]"
                     if identity["validation"]["warnings"] else "")
                print("  " + s + "  "
                      + identity["agent"]["display_name"].ljust(14)
                      + identity["agent"]["role"] + w)
        if not args.json:
            print("\n" + str(passed) + "/" + str(len(eco))
                  + " agents loaded successfully")
        return

    if args.show:
        identity = load_agent(args.show, repo_root=root)
        if args.json or args.export:
            out = json.dumps(identity, indent=2)
            if args.export:
                Path(args.export).write_text(out, encoding="utf-8")
                print("Exported to " + args.export)
            else:
                print(out)
        else:
            print(_summary(identity))
        return

    if args.validate:
        identity = load_agent(args.validate, repo_root=root)
        val = identity["validation"]
        print("\nValidation: " + ("PASS" if val["passed"] else "FAIL"))
        for e in val["errors"]:
            print("  ERROR [" + e["rule_id"] + "] " + e["message"])
        for w in val["warnings"]:
            print("  WARN  [" + w["rule_id"] + "] " + w["message"])
        if val["passed"] and not val["warnings"]:
            print("  All checks passed.")
        sys.exit(0 if val["passed"] else 1)
        return

    p.print_help()


if __name__ == "__main__":
    main()
